previewCss:
.darma-loader-darma-custom-461 {color: var(--loader-color, #7c3aed);
  --loader-secondary-color: var(--loader-secondary-color, #c084fc);
  --loader-bg: var(--loader-bg, #ffffff);
   width: 50px;
   aspect-ratio: 1;
   background: var(--loader-color, #7c3aed);
   border-radius: 50%;
   display: grid;
}
.darma-loader-darma-custom-461::before, .darma-loader-darma-custom-461::after  {
  content: "";
   grid-area: 1/1;
   background: inherit;
   clip-path: polygon(0 0,50% 40%,100% 0,60% 50%,100% 100%,50% 60%,0 100%,40% 50%);
   animation: darma-loader-darma-custom-461-l1 1s infinite alternate;
   transform: rotate(var(--r,0)) scale(1) }
.darma-loader-darma-custom-461::after  {
  --r:45deg;
}
@keyframes darma-loader-darma-custom-461-l1  {
  100% {transform:rotate(var(--r,0)) scale(1.4) }
}

